/// <summary>
/// Extension of the <c>init</c> method for the ETG model.
/// </summary>
/// <remarks>This code is used to show or hide features in Spanish companies.</remarks>
public void init()
{
    next init();
    NoYesId currentCompanyIsSpanishCompany  = CurrentCompanyIsSpanishCompany();

    this.design().controlName(formControlStr(PurchTable, ETGSPAINPorts)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchTable, ETGSPAINPorts_ETGSPAINPurchLoadPortId)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchTable, ETGSPAINPorts_ETGSPAINPurchUnloadPortId)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(PurchTable, ETGSPAINPlate)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchTable, ETGSPAINPlate_ETGSPAINPlateDueDate)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchTable, ETGSPAINPlate_ETGSPAINPlateFromDate)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(PurchTable, ETGSPAINExecution)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchTable, ETGSPAINExecution_ETGSPAINPurchExecutionDueDate)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchTable, ETGSPAINExecution_ETGSPAINPurchExecutionFromDate)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(PurchTable, ETGSPAINUnsoldInventTransModifyController)).visible(currentCompanyIsSpanishCompany);
}
